    size_t e = p;
    if (e < block.size() && block[e] == '-') ++e;
    while (e < block.size() && std::isdigit(static_cast<unsigned char>(block[e]))) {
        ++e;
    }
    return std::stoi(block.substr(p, e - p));
}

