    if (units_pos == std::string::npos) {
        return state;
    }
    size_t arr_start = doc.find('[', units_pos);
    size_t arr_end = doc.find(']', arr_start);
    if (arr_start == std::string::npos || arr_end == std::string::npos) {
        return state;
