    size_t e = p;
    if (e < block.size() && block[e] == '-') ++e;
    while (e < block.size() && std::isdigit(static_cast<unsigned char>(block[e]))) {
        ++e;
    }
    return std::stoll(block.substr(p, e - p));
}

std::vector<std::string> split_object_blocks(const std::string &array_text) {
    std::vector<std::string> out;
    int depth = 0;
    size_t start = std::string::npos;
    for (size_t i = 0; i < array_text.size(); ++i) {
        if (array_text[i] == '{') {
            if (depth == 0) {
                start = i;
            }
            ++depth;
        } else if (array_text[i] == '}') {
            --depth;
            if (depth == 0 && start != std::string::npos) {
                out.push_back(array_text.substr(start, i - start + 1));
