extern "C" const char *m14_lane_token(const forge::UnitSpec *units, size_t count) {
    static std::string cached;
    // Build descriptor lines and sort them alphabetically by unit name
    std::vector<std::pair<std::string, std::string>> name_lines;
    for (size_t i = 0; i < count; ++i) {
        name_lines.emplace_back(units[i].name, descriptor_line(units[i]));
    }
    std::sort(name_lines.begin(), name_lines.end(),
              [](const std::pair<std::string, std::string> &a,
                 const std::pair<std::string, std::string> &b) {
                  return a.first < b.first;
              });
    std::ostringstream joined;
    for (size_t i = 0; i < name_lines.size(); ++i) {
        if (i) {
            joined << '\n';
        }
        joined << name_lines[i].second;
    }
    cached = digest_hex(joined.str());
    return cached.c_str();
}

