    // Start with existing checkpoint entries
    std::map<std::string, forge::UnitCheckpoint> merged;
    if (existing.valid) {
        for (const auto &pair : existing.units) {
            merged[pair.first] = pair.second;
        }
    }
    // Overwrite with updated entries
    for (const auto &entry : updated) {
        merged[entry.name] = entry;
    }
    // Convert to sorted vector
    std::vector<forge::UnitCheckpoint> out;
    for (const auto &pair : merged) {
        out.push_back(pair.second);
    }
    std::sort(out.begin(), out.end(),
              [](const forge::UnitCheckpoint &a, const forge::UnitCheckpoint &b) {
                  return a.name < b.name;
